import React from 'react'

function Eachimage(props) {
    return (
        <>
            <img src={props.link} className="anal_img" />
        </>
    )
}

function Analytic() {

    const [Images_array, setImages_array] = useState([])

    async function get_string() {
        fetch("http://localhost:5000/anal")
            .then(data => {
                return data.json();
            })
            .then(post => {
                setImages_array(post)
            });
    }

    return (
        <div className='analytics_master'>
            {Images_array.map(each => (Eachimage))}
            <button onClick={get_string}>Get analytics</button>
        </div>
    )
}

export default Analytic
